UPDATE trading_registry r
SET applies_to = scope_updates.new_applies_to,
    updated_at = CURRENT_TIMESTAMP
FROM scope_updates
WHERE r.id = scope_updates.id
  AND r.kind = 'state_vector_value'
  AND r.applies_to IS DISTINCT FROM scope_updates.new_applies_to;

