UPDATE trading_registry r
SET key = value_updates.new_key,
    payload = value_updates.new_payload,
    updated_at = CURRENT_TIMESTAMP
FROM value_updates
WHERE r.id = value_updates.id
  AND r.kind = 'state_vector_value'
  AND (r.key IS DISTINCT FROM value_updates.new_key
       OR r.payload IS DISTINCT FROM value_updates.new_payload);
